  # }

if(!is.null(x$A)){
  sp<-Matrix::summary(x$A) # sparse representation of A
  sp2<-sp[sp[,1]!=sp[,2],]
  hist(sp2[,3], breaks=seq(0,1,0.05), xlab="Distribution of relatedness across the pedigree", main="")
  inp <- readline(prompt = "Press <s> to save current plot or press <Enter> to continue...")
    if (inp == "s") {
